@startuml
skinparam classAttributeIconSize 0

class Game << (C,#b6e3b6) C >>

interface PropFactory << (I,#c7b6ff) I >> {
  + create(int x,int y):AbstractProp
}

abstract class AbstractProp << (A,#b6e3ff) A >> {
  - propkind
  + AbstractProp(int locationX, int locationY, int speedX, int speedY):void
  + getPropkind():int
}

class BloodFactory << (C,#b6e3b6) C >> {
  + create(int x,int y):BloodProp
}

class BombFactory << (C,#b6e3b6) C >> {
  + create(int x,int y):BombProp
}

class FireFactory << (C,#b6e3b6) C >> {
  + create(int x,int y):FireProp
}

class BloodProp << (C,#b6e3b6) C >> {
  - propkind
  + BloodTool(int locationX, int locationY, int speedX, int speedY):void
}

class BombProp << (C,#b6e3b6) C >> {
  - propkind
  + BombProp(int locationX, int locationY, int speedX, int speedY):void
}

class FireProp << (C,#b6e3b6) C >> {
  - propkind
  + FireTool(int locationX, int locationY, int speedX, int speedY):void
}

Game ..> PropFactory
Game ..> AbstractProp

BloodFactory ..|> PropFactory
BombFactory ..|> PropFactory
FireFactory ..|> PropFactory

BloodProp --|> AbstractProp
BombProp --|> AbstractProp
FireProp --|> AbstractProp

BloodFactory ..> BloodProp : create
BombFactory ..> BombProp : create
FireFactory ..> FireProp : create
@enduml
